// Code node n8n
// Objetivo: gerar buscas por múltiplos sites, nicho e DDD sem duplicar query
// Adicional: gerar também buscas livres sem site:
// Exemplo: (advogado) AND (telefone|fone|phone|tel|contato|fixo|móvel|whatsapp|whats|zap)
//
// Entrada esperada:
// $json.nicho
// $json.site ou $json.sites
//
// Exemplo:
// site: consultas.plus|instagram.com|br.todosnegocios.com

const input = $input.first()?.json || {};

const nicho = String(input.nicho || '').trim();
const sitesRaw = String(input.sites || input.site || '').trim();

if (!nicho) {
  throw new Error('Campo obrigatório ausente: $json.nicho');
}

if (!sitesRaw) {
  throw new Error('Campo obrigatório ausente: $json.site ou $json.sites');
}

function normalizarSite(site) {
  return String(site || '')
    .trim()
    .replace(/^https?:\/\//i, '')
    .replace(/^www\./i, '')
    .replace(/\/+$/g, '');
}

function parseSites(sitesRaw) {
  const sites = String(sitesRaw || '')
    .split('|')
    .map(normalizarSite)
    .filter(Boolean);

  return [...new Set(sites)];
}

function isInstagramSite(site) {
  const s = String(site || '').toLowerCase();

  return (
    s === 'instagram.com' ||
    s.startsWith('instagram.com/') ||
    s.endsWith('.instagram.com')
  );
}

const sites = parseSites(sitesRaw);

if (!sites.length) {
  throw new Error('Nenhum site válido encontrado em $json.site ou $json.sites');
}

