function montarGrupoOu(termos) {
  return termos
    .map(termo => String(termo || '').trim())
    .filter(Boolean)
    .join('|');
}

const grupoContato = montarGrupoOu(termosContato);
const grupoSimbolosWhatsapp = montarGrupoOu(termosSimbolosWhatsapp);

function filtrosPorSite(site) {
  return isInstagramSite(site)
    ? ' -inurl:/reel -inurl:/post -inurl:/p/'
    : '';
}

function gerarQueriesLivresGerais({ nicho }) {
  return [
    {
      escopo_query: 'livre_sem_site',
      tipo_query: 'livre_contato',
      q: `(${nicho}) AND (${grupoContato})`,
    },
    {
      escopo_query: 'livre_sem_site',
      tipo_query: 'livre_simbolos_whatsapp',
      q: `(${nicho}) AND (${grupoSimbolosWhatsapp})`,
    },
  ];
}

function gerarQueriesLivresPorDdd({ nicho, ddd }) {
  const dddComZero = `0${ddd}`;
  const dddCelular = `${ddd}9`;
  const formatosDdd = `${ddd}|${dddComZero}|${dddCelular}`;

  return [
    {
      escopo_query: 'livre_por_ddd',
      tipo_query: 'livre_ddd_apenas',
      q: `(${nicho}) AND (${formatosDdd})`,
    },
    {
      escopo_query: 'livre_por_ddd',
      tipo_query: 'livre_ddd_telefone',
      q: `(${nicho}) AND (${grupoContato} + ${formatosDdd})`,
    },
    {
      escopo_query: 'livre_por_ddd',
      tipo_query: 'livre_ddd_whatsapp',
      q: `(${nicho}) AND (whatsapp|whats|zap|wpp + ${formatosDdd})`,
    },
  ];
}

function gerarQueriesGerais({ site, nicho }) {
  const filtrosInstagram = filtrosPorSite(site);

  return [
    {
      escopo_query: 'geral_sem_ddd',
      tipo_query: 'geral_contato',
      q: `site:${site}${filtrosInstagram} (${nicho}) AND (${grupoContato})`,
    },
    {
      escopo_query: 'geral_sem_ddd',
      tipo_query: 'geral_simbolos_whatsapp',
      q: `site:${site}${filtrosInstagram} (${nicho}) AND (${grupoSimbolosWhatsapp})`,
    },
  ];
}

function gerarQueriesPorDdd({ site, nicho, ddd }) {
  const filtrosInstagram = filtrosPorSite(site);

  const dddComZero = `0${ddd}`;
  const dddCelular = `${ddd}9`;
  const formatosDdd = `${ddd}|${dddComZero}|${dddCelular}`;

  return [
    {
      escopo_query: 'por_ddd',
      tipo_query: 'ddd_apenas',
      q: `site:${site}${filtrosInstagram} (${nicho}) AND (${formatosDdd})`,
