// Code node n8n
// Extrai telefones e e-mails de textos do JSON sem confundir CNPJ/CPF com telefone

const items = $input.all();

const URL_KEYS = new Set([
  'link',
  'url',
  'href',
  'displayed_link',
  'thumbnail',
  'favicon',
  'image',
]);

function coletarTextos(obj) {
  const textos = [];

  function walk(value, key = '') {
    if (value == null) return;

    const keyLower = String(key || '').toLowerCase();

    // Evita capturar CNPJ/IDs dentro de URLs
    if (URL_KEYS.has(keyLower)) return;

    if (typeof value === 'string') {
      textos.push(value);
      return;
    }

    if (Array.isArray(value)) {
      value.forEach((v) => walk(v, key));
      return;
    }

    if (typeof value === 'object') {
      Object.entries(value).forEach(([k, v]) => walk(v, k));
    }
  }

  walk(obj);
  return textos;
}

function limparEmail(raw) {
  return String(raw || '')
    .toLowerCase()
    .replace(/^[<("'[\s]+/g, '')
    .replace(/[>")'\]\s.,;:!?]+$/g, '')
    .trim();
}

function extrairEmailsDoTexto(textoOriginal) {
  const texto = String(textoOriginal || '').normalize('NFKC');

  const regex = /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi;
  const matches = texto.match(regex) || [];

  return matches
    .map(limparEmail)
    .filter((email) => {
      if (!email) return false;
      if (!email.includes('@')) return false;

      // Evita falso positivo tosco
      if (email.includes('example.com')) return false;
      if (email.includes('email.com')) return false;

      return true;
    })
    .map((email) => ({
      email,
      email_normalizado: email,
    }));
}

function prepararTexto(texto) {
  return String(texto || '')
    // Remove URLs inteiras
    .replace(/https?:\/\/\S+/gi, ' ')

    // Remove e-mails para não pegar números perto do e-mail
    .replace(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi, ' ')

    // Remove CNPJ formatado: 50.107.766/0001-48
    .replace(/\b\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}\b/g, ' ')

    // Remove CPF formatado: 123.456.789-00
    .replace(/\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g, ' ')

    // Remove sequências de 14 dígitos, normalmente CNPJ puro
    .replace(/\b\d{14}\b/g, ' ');
}

function somenteDigitos(raw) {
  return String(raw || '').replace(/\D/g, '');
}

function limparTelefoneBruto(raw) {
  return String(raw || '')
    .replace(/\s+/g, ' ')
    .replace(/\s*-\s*/g, '-')
    .replace(/[;,.]+$/g, '')
    .trim();
}

function normalizarTelefone(raw) {
  let digits = somenteDigitos(raw);

  // Remove prefixo 00, comum em cópias ruins
  digits = digits.replace(/^00+/, '');

  // Se vier com +55 ou 55
  if (digits.startsWith('55')) {
    let nacional = digits.slice(2);

    // Remove zero antes do DDD: 011999999999
    nacional = nacional.replace(/^0(?=\d{10,11}$)/, '');

    if (nacional.length === 10 || nacional.length === 11) {
      return `+55${nacional}`;
    }
  }

  // Remove zero antes do DDD: 011999999999
  digits = digits.replace(/^0(?=\d{10,11}$)/, '');

  // Telefone brasileiro com DDD
  if (digits.length === 10 || digits.length === 11) {
    return `+55${digits}`;
  }

  // Números especiais
  if (/^(0800|0300|0500|400[0-9]|300[0-9])/.test(digits)) {
    return digits;
  }

  return digits;
}

function temContextoTelefone(texto, index, tamanho) {
  const inicio = Math.max(0, index - 45);
  const fim = Math.min(texto.length, index + tamanho + 25);
  const contexto = texto.slice(inicio, fim).toLowerCase();

  return /(telefone|tel|fone|whatsapp|whats|zap|celular|cel|contato|ligue|call|phone|mobile|móvel)/i.test(contexto);
}

function temFormatoTelefonico(raw) {
  const texto = String(raw || '');

  return (
    /\(\s*0?[1-9]{2}\s*\)/.test(texto) || // Ex: (48)
    /\d{4,5}\s*[-.\s]\s*\d{4}/.test(texto) // Ex: 9940-7222
  );
}

function isTelefoneValido(raw, texto = '', index = 0, exigeContexto = false) {
  const bruto = String(raw || '');
  const digitsOriginal = somenteDigitos(bruto);

  if (!digitsOriginal) return false;

  const contextoOk = temContextoTelefone(texto, index, bruto.length);
  const formatoOk = temFormatoTelefonico(bruto);

  // Bloqueia CNPJ puro quando não tem cara de telefone
  if (digitsOriginal.length === 14 && !digitsOriginal.startsWith('55')) {
    return false;
  }

  // Bloqueia CPF puro quando não tem contexto nem formatação de telefone
  if (digitsOriginal.length === 11 && !contextoOk && !formatoOk) {
    const ddd = Number(digitsOriginal.slice(0, 2));
    const nonoDigito = digitsOriginal[2];

    if (!(ddd >= 11 && ddd <= 99 && nonoDigito === '9')) {
      return false;
    }
  }

  let digits = digitsOriginal;

  if (digits.startsWith('55')) {
    digits = digits.slice(2);
  }

  // Remove zero antes do DDD: 011999999999
  digits = digits.replace(/^0(?=\d{10,11}$)/, '');

  if (exigeContexto && !contextoOk && !formatoOk) {
    return false;
  }

  // Telefone com DDD e 8 dígitos locais
  // Ex: (11) 5370-8704
  // Ex: (48) 9940-7222
  if (digits.length === 10) {
    const ddd = Number(digits.slice(0, 2));
    const primeiroLocal = digits[2];

    if (ddd < 11 || ddd > 99) return false;

    // Se tem contexto ou está claramente formatado como telefone, aceita 2 a 9
    if (contextoOk || formatoOk) {
      return /[2-9]/.test(primeiroLocal);
    }

    // Sem contexto e sem formatação, fica mais conservador
    return /[2-5]/.test(primeiroLocal);
  }

  // Celular com DDD e 9 dígitos locais
  // Ex: (11) 94701-2008
  if (digits.length === 11) {
    const ddd = Number(digits.slice(0, 2));
    const primeiroLocal = digits[2];

    if (ddd < 11 || ddd > 99) return false;

    if (contextoOk || formatoOk) {
      return /[6-9]/.test(primeiroLocal);
    }

    return primeiroLocal === '9';
  }

  // 0800, 0300, 0500
  if (/^(0800|0300|0500)\d{6,7}$/.test(digits)) {
    return true;
  }

  // 4004-0000, 3003-0000
  if (/^(400[0-9]|300[0-9])\d{4}$/.test(digits)) {
    return true;
  }

  return false;
}

function extrairTelefonesDoTexto(textoOriginal) {
  const texto = prepararTexto(textoOriginal);
  const resultados = [];

  const patterns = [
    {
      nome: 'telefone_com_ddd_formatado',
      exigeContexto: false,
      regex: /(?:\+?\s*55\s*)?\(?\s*0?[1-9]{2}\s*\)?[\s.-]+9?\d{4,5}\s*[-.\s]?\s*\d{4}/g,
    },
    {
      nome: 'telefone_continuo_com_contexto',
      exigeContexto: true,
      regex: /(?:\+?\s*55\s*)?0?[1-9]{2}9?\d{8,9}/g,
    },
    {
      nome: 'telefone_especial',
      exigeContexto: false,
      regex: /(?:0800|0300|0500)\s*\d{3}\s*[-.\s]?\s*\d{4}|(?:400[0-9]|300[0-9])\s*[-.\s]?\s*\d{4}/g,
    },
  ];

  for (const pattern of patterns) {
    let match;

    while ((match = pattern.regex.exec(texto)) !== null) {
      const bruto = limparTelefoneBruto(match[0]);
      const index = match.index;

      if (!isTelefoneValido(bruto, texto, index, pattern.exigeContexto)) {
        continue;
      }

      resultados.push({
        telefone_bruto: bruto,
        telefone_digitos: somenteDigitos(bruto),
        telefone_normalizado: normalizarTelefone(bruto),
        origem_pattern: pattern.nome,
      });
    }
  }

  return resultados;
}

function obterRegistros(data) {
  if (Array.isArray(data)) return data;
  if (Array.isArray(data.organic)) return data.organic;
  if (Array.isArray(data.local_results)) return data.local_results;
  if (Array.isArray(data.places_results)) return data.places_results;
  return [data];
}

const saida = [];

for (const item of items) {
  const registros = obterRegistros(item.json);

  for (const registro of registros) {
    const textos = coletarTextos(registro);

    const telefones = [];
    const emails = [];

    for (const texto of textos) {
      emails.push(...extrairEmailsDoTexto(texto));
      telefones.push(...extrairTelefonesDoTexto(texto));
    }

    const telefonesUnicos = Array.from(
      new Map(
        telefones.map((tel) => [tel.telefone_normalizado, tel])
      ).values()
    );

    const emailsUnicos = Array.from(
      new Map(
        emails.map((email) => [email.email_normalizado, email])
      ).values()
    );

    saida.push({
      json: {
        ...registro,

        telefones: telefonesUnicos,
        telefones_brutos: telefonesUnicos.map((t) => t.telefone_bruto),
        telefones_normalizados: telefonesUnicos.map((t) => t.telefone_normalizado),
        telefone_principal: telefonesUnicos[0]?.telefone_normalizado || null,
        tem_telefone: telefonesUnicos.length > 0,

        emails: emailsUnicos,
        emails_normalizados: emailsUnicos.map((e) => e.email_normalizado),
        email_principal: emailsUnicos[0]?.email_normalizado || null,
        tem_email: emailsUnicos.length > 0,
      },
    });
  }
}

return saida;

