    data.searchParameters?.gl ||
    'br'
  );
}

function extrairHl(data) {
  return (
    data.hl ||
    data.serpapi_params?.hl ||
    data.searchParameters?.hl ||
    'pt-br'
  );
}

function extrairPage(data) {
  return Number(
    data.page ||
    data.serpapi_params?.page ||
    data.searchParameters?.page ||
    1
  );
}

function adicionar(data) {
  const q = String(extrairQuery(data) || '').replace(/\s+/g, ' ').trim();

  if (!q) return;

  // Evita duplicar a mesma busca
  if (queriesJaVistas.has(q)) return;

  queriesJaVistas.add(q);

  saida.push({
    q,
    gl: String(extrairGl(data) || 'br').trim(),
    hl: String(extrairHl(data) || 'pt-br').trim(),
    page: extrairPage(data),
    engine: "google.com.br",
  });
}

for (const item of items) {
  const data = item.json;

  // Caso venha um array inteiro dentro do item
  if (Array.isArray(data)) {
    data.forEach(adicionar);
    continue;
  }

  // Caso venha normal, um item por vez
  adicionar(data);
}

return [
  {
    json: {
      queries: saida,
      total_queries: saida.length,
    },
  },
];
